import 'package:flutter/material.dart';import '../services/api_service.dart';
class LoginScreen extends StatefulWidget{final VoidCallback onLogin;const LoginScreen({super.key,required this.onLogin});@override State<LoginScreen> createState()=>_LoginScreenState();}class _LoginScreenState extends State<LoginScreen>{final email=TextEditingController(text:'admin@orbe.com');final password=TextEditingController(text:'admin123');bool loading=false;String? error;Future<void> submit()async{setState((){loading=true;error=null;});try{await ApiService.instance.login(email.text,password.text);widget.onLogin();}catch(e){setState(()=>error=e.toString().replaceFirst('Exception: ',''));}finally{if(mounted)setState(()=>loading=false);}}@override Widget build(BuildContext context)=>Scaffold(body:SafeArea(child:Padding(padding:const EdgeInsets.all(28),child:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[const Spacer(),Container(width:54,height:54,decoration:BoxDecoration(color:const Color(0xffc9f270),borderRadius:BorderRadius.circular(16)),child:const Icon(Icons.restaurant)),const SizedBox(height:22),Text('orbe',style:Theme.of(context).textTheme.headlineLarge?.copyWith(fontWeight:FontWeight.bold)),const Text('Aplicativo do garçom'),const SizedBox(height:35),TextField(controller:email,keyboardType:TextInputType.emailAddress,decoration:const InputDecoration(labelText:'E-mail',border:OutlineInputBorder())),const SizedBox(height:12),TextField(controller:password,obscureText:true,decoration:const InputDecoration(labelText:'Senha',border:OutlineInputBorder())),if(error!=null)Padding(padding:const EdgeInsets.only(top:12),child:Text(error!,style:const TextStyle(color:Colors.red))),const SizedBox(height:16),SizedBox(width:double.infinity,height:52,child:FilledButton(onPressed:loading?null:submit,child:Text(loading?'Entrando...':'Entrar na operação'))),const Spacer()]))) );}
